    /**
     */
    private fun _getBendPoints(importer: com.omnifret.gplayer.importer.gplayertex.IGPlayerTexImporter, p: com.omnifret.gplayer.importer.gplayertex.GPlayerTexPropertyNode, argStartIndex: Double, exact: Boolean): com.omnifret.gplayer.collections.List<com.omnifret.gplayer.model.BendPoint>?{
        var paramargStartIndex = argStartIndex
        var args: com.omnifret.gplayer.collections.List<com.omnifret.gplayer.importer.gplayertex.IGPlayerTexArgumentValue> = p.arguments!!.arguments
        var remainingArgs: Double = args.length - paramargStartIndex
        var errorNode: com.omnifret.gplayer.importer.gplayertex.GPlayerTexAstNode = p.arguments!!
        if (remainingArgs > 0 && args[(paramargStartIndex).toInt()].nodeType == com.omnifret.gplayer.importer.gplayertex.GPlayerTexNodeType.Arguments)
        {
            args = ((args[(paramargStartIndex).toInt()] as com.omnifret.gplayer.importer.gplayertex.GPlayerTexArgumentList)).arguments
            paramargStartIndex = 0.0
            remainingArgs = args.length
            errorNode = (args[(paramargStartIndex).toInt()] as com.omnifret.gplayer.importer.gplayertex.GPlayerTexAstNode)
        }
        var argsPerItem: Double = if(exact)  2.0 else 1.0
        if (remainingArgs % argsPerItem != 0.0)
        {
            var pointCount: Double = com.omnifret.gplayer.core.ecmaScript.Math.ceil(remainingArgs / argsPerItem)
            var neededArgs: Double = pointCount * argsPerItem
            importer.addSemanticDiagnostic(com.omnifret.gplayer.importer.gplayertex.GPlayerTexDiagnostic(code = com.omnifret.gplayer.importer.gplayertex.GPlayerTexDiagnosticCode.AT214, message = """The '${(p.property.text).toTemplate()}' effect needs ${(argsPerItem).toTemplate()} arguments per item. With ${(pointCount).toTemplate()} points, ${(neededArgs).toTemplate()} arguments are needed, only ${(remainingArgs).toTemplate()} arguments found.""", severity = com.omnifret.gplayer.importer.gplayertex.GPlayerTexDiagnosticsSeverity.Error, start = errorNode!!.end, end = errorNode!!.end))
            return null
        }
        var points: com.omnifret.gplayer.collections.List<com.omnifret.gplayer.model.BendPoint> = com.omnifret.gplayer.collections.List<com.omnifret.gplayer.model.BendPoint>(
        )
        
        var vi: Double = paramargStartIndex
        while (vi < args.length)
        {
            var offset: Double = 0.0
            var value: Double = 0.0
            if (exact)
            {
                offset = ((args[(vi++).toInt()] as com.omnifret.gplayer.importer.gplayertex.GPlayerTexNumberLiteral)).value
                value = ((args[(vi++).toInt()] as com.omnifret.gplayer.importer.gplayertex.GPlayerTexNumberLiteral)).value
            }
            else 
            {
                offset = 0.0
                value = ((args[(vi++).toInt()] as com.omnifret.gplayer.importer.gplayertex.GPlayerTexNumberLiteral)).value
            }
            points.push(com.omnifret.gplayer.model.BendPoint(offset, value))
        }
        if (points.length > 0)
        {
            if (points.length > 60)
            {
                points.splice(60.0, points.length - (60.0).toDouble())
            }
            if (exact)
            {
                points.sort(fun(a: com.omnifret.gplayer.model.BendPoint, b: com.omnifret.gplayer.model.BendPoint): Double{
                    return a.offset - b.offset
                }
                )
            }
            else 
            {
                var count: Double = points.length
                var step: Double = (((com.omnifret.gplayer.model.BendPoint.MaxPosition / (count - (1.0).toDouble()))).toInt() or 0).toDouble()
                var i: Double = 0.0
                while (i < count)
                {
                    points[(i).toInt()].offset = com.omnifret.gplayer.core.ecmaScript.Math.min(com.omnifret.gplayer.model.BendPoint.MaxPosition, i * step)
                    i++
                }
            }
            return points
        }
        else 
        {
            return null
        }
    }
    
