        )
        
        com.omnifret.gplayer.importer.gplayertex.GPlayerTex1LanguageHandler._buildStructuralMetaDataNodes(bar, staff, nodes, isMultiVoice, voice)
        if (!com.omnifret.gplayer.core.TypeHelper.isTruthy(com.omnifret.gplayer.core.TypeHelper.isTruthy(bar)))
        {
            return nodes
        }
        if (voice == 0.0)
        {
            if (staff.index == 0.0 && staff.track.index == 0.0)
            {
                com.omnifret.gplayer.importer.gplayertex.GPlayerTex1LanguageHandler._buildMasterBarMetaDataNodes(nodes, bar!!.masterBar)
            }
        }
        var firstBarMetaIndex: Double = nodes.length
        if (voice == 0.0 && bar!!.index == 0.0 && staff.index == 0.0 && staff.track.index == 0.0)
        {
            nodes.push(com.omnifret.gplayer.importer.gplayertex.Atnf.identMeta("accidentals", "auto"))
