        {
            nodes.push(com.omnifret.gplayer.importer.gplayertex.Atnf.identMeta("clef", com.omnifret.gplayer.importer.gplayertex.GPlayerTex1EnumMappings.clefReversed.get(bar!!.clef)!!))
        }
        if ((bar!!.index == 0.0 && bar!!.clefOttava != com.omnifret.gplayer.model.Ottavia.Regular) || bar!!.clefOttava != bar!!.previousBar?.clefOttava)
        {
            nodes.push(com.omnifret.gplayer.importer.gplayertex.Atnf.identMeta("ottava", com.omnifret.gplayer.importer.gplayertex.GPlayerTex1EnumMappings.ottaviaReversed.get(bar!!.clefOttava)!!))
        }
