        {
            nodes.push(com.omnifret.gplayer.importer.gplayertex.Atnf.numberMeta("width", bar!!.displayWidth))
        }
        for (sp in bar!!.sustainPedals)
        {
            var pedalType: String = ""
            when (sp.pedalType)
            {
                com.omnifret.gplayer.model.SustainPedalMarkerType.Down -> 
                {
                    pedalType = "spd"
                }
                com.omnifret.gplayer.model.SustainPedalMarkerType.Hold -> 
