                    pedalType = "spu"
                }
                else -> { }
            }
            if (com.omnifret.gplayer.core.TypeHelper.isTruthy(com.omnifret.gplayer.core.TypeHelper.isTruthy(pedalType)))
            {
                nodes.push(com.omnifret.gplayer.importer.gplayertex.Atnf.numberMeta(pedalType, sp.ratioPosition))
            }
        }
        if (bar!!.barLineLeft != com.omnifret.gplayer.model.BarLineStyle.Automatic)
        {
            nodes.push(com.omnifret.gplayer.importer.gplayertex.Atnf.identMeta("barLineLeft", com.omnifret.gplayer.importer.gplayertex.GPlayerTex1EnumMappings.barLineStyleReversed.get(bar!!.barLineLeft)!!))
        }
        if (bar!!.barLineRight != com.omnifret.gplayer.model.BarLineStyle.Automatic)
        {
            nodes.push(com.omnifret.gplayer.importer.gplayertex.Atnf.identMeta("barLineRight", com.omnifret.gplayer.importer.gplayertex.GPlayerTex1EnumMappings.barLineStyleReversed.get(bar!!.barLineRight)!!))
        }
        if (bar!!.index == 0.0 || bar!!.keySignature != bar!!.previousBar!!.keySignature || bar!!.keySignatureType != bar!!.previousBar!!.keySignatureType)
        {
            var ks: String = ""
            if (bar!!.keySignatureType == com.omnifret.gplayer.model.KeySignatureType.Minor)
            {
                ks = com.omnifret.gplayer.importer.gplayertex.GPlayerTex1EnumMappings.keySignaturesMinorReversed.get(bar!!.keySignature)!!
            }
            else 
            {
                ks = com.omnifret.gplayer.importer.gplayertex.GPlayerTex1EnumMappings.keySignaturesMajorReversed.get(bar!!.keySignature)!!
            }
            nodes.push(com.omnifret.gplayer.importer.gplayertex.Atnf.identMeta("ks", ks))
        }
        if (firstBarMetaIndex < nodes.length)
        {
            nodes[(firstBarMetaIndex).toInt()].leadingComments = com.omnifret.gplayer.collections.List<com.omnifret.gplayer.importer.gplayertex.GPlayerTexComment>(
                com.omnifret.gplayer.importer.gplayertex.GPlayerTexComment(multiLine = false, text = """Bar ${(bar!!.index + 1.0).toTemplate()} Metadata"""))
            
        }
        if (bar!!.barNumberDisplay != null)
        {
            nodes.push(com.omnifret.gplayer.importer.gplayertex.Atnf.identMeta("barNumberDisplay", bar!!.barNumberDisplay!!.toString()))
        }
        return nodes
    }
    
    /**
     */
    public override fun buildNoteEffects(note: com.omnifret.gplayer.model.Note): com.omnifret.gplayer.collections.List<com.omnifret.gplayer.importer.gplayertex.GPlayerTexPropertyNode>{
        var properties: com.omnifret.gplayer.collections.List<com.omnifret.gplayer.importer.gplayertex.GPlayerTexPropertyNode> = com.omnifret.gplayer.collections.List<com.omnifret.gplayer.importer.gplayertex.GPlayerTexPropertyNode>(
        )
        
        if (note.hasBend)
        {
