                com.omnifret.gplayer.importer.gplayertex.Atnf.ident(com.omnifret.gplayer.importer.gplayertex.GPlayerTex1EnumMappings.bendTypeReversed.get(note.bendType)!!), if(note.bendStyle != com.omnifret.gplayer.model.BendStyle.Default)  com.omnifret.gplayer.importer.gplayertex.Atnf.ident(com.omnifret.gplayer.importer.gplayertex.GPlayerTex1EnumMappings.bendStyleReversed.get(note.bendStyle)!!) else null)
            , true)!!
            for (p in note.bendPoints!!)
            {
                beValue.arguments.push(com.omnifret.gplayer.importer.gplayertex.Atnf.number(p.offset))
                beValue.arguments.push(com.omnifret.gplayer.importer.gplayertex.Atnf.number(p.value))
            }
            com.omnifret.gplayer.importer.gplayertex.Atnf.prop(properties, "be", beValue)
        }
        var harmonicType: String = ""
        when (note.harmonicType)
        {
            com.omnifret.gplayer.model.HarmonicType.Natural -> 
            {
                com.omnifret.gplayer.importer.gplayertex.Atnf.prop(properties, "nh")
            }
            com.omnifret.gplayer.model.HarmonicType.Artificial -> 
            {
                harmonicType = "ah"
            }
            com.omnifret.gplayer.model.HarmonicType.Pinch -> 
            {
                harmonicType = "ph"
            }
            com.omnifret.gplayer.model.HarmonicType.Tap -> 
            {
                harmonicType = "th"
            }
            com.omnifret.gplayer.model.HarmonicType.Semi -> 
            {
                harmonicType = "sh"
            }
            com.omnifret.gplayer.model.HarmonicType.Feedback -> 
            {
                harmonicType = "fh"
            }
            else -> { }
        }
        if (com.omnifret.gplayer.core.TypeHelper.isTruthy(com.omnifret.gplayer.core.TypeHelper.isTruthy(harmonicType)))
        {
            com.omnifret.gplayer.importer.gplayertex.Atnf.prop(properties, harmonicType, com.omnifret.gplayer.importer.gplayertex.Atnf.numberValue(note.harmonicValue))
        }
        if (note.showStringNumber)
        {
            com.omnifret.gplayer.importer.gplayertex.Atnf.prop(properties, "string")
        }
        if (note.isTrill)
        {
            com.omnifret.gplayer.importer.gplayertex.Atnf.prop(properties, "tr", com.omnifret.gplayer.importer.gplayertex.Atnf.args(com.omnifret.gplayer.collections.List<com.omnifret.gplayer.importer.gplayertex.IGPlayerTexArgumentValue?>(
                com.omnifret.gplayer.importer.gplayertex.Atnf.number(note.trillFret), com.omnifret.gplayer.importer.gplayertex.Atnf.number(note.trillSpeed.toDouble()))
            ))
        }
        when (note.vibrato)
        {
            com.omnifret.gplayer.model.VibratoType.Slight -> 
            {
                com.omnifret.gplayer.importer.gplayertex.Atnf.prop(properties, "v")
            }
            com.omnifret.gplayer.model.VibratoType.Wide -> 
            {
                com.omnifret.gplayer.importer.gplayertex.Atnf.prop(properties, "vw")
            }
            else -> { }
        }
        when (note.slideInType)
        {
            com.omnifret.gplayer.model.SlideInType.IntoFromBelow -> 
            {
                com.omnifret.gplayer.importer.gplayertex.Atnf.prop(properties, "sib")
            }
            com.omnifret.gplayer.model.SlideInType.IntoFromAbove -> 
            {
                com.omnifret.gplayer.importer.gplayertex.Atnf.prop(properties, "sia")
            }
            else -> { }
        }
        when (note.slideOutType)
        {
            com.omnifret.gplayer.model.SlideOutType.Shift -> 
            {
                com.omnifret.gplayer.importer.gplayertex.Atnf.prop(properties, "ss")
            }
            com.omnifret.gplayer.model.SlideOutType.Legato -> 
            {
                com.omnifret.gplayer.importer.gplayertex.Atnf.prop(properties, "sl")
            }
            com.omnifret.gplayer.model.SlideOutType.OutUp -> 
            {
                com.omnifret.gplayer.importer.gplayertex.Atnf.prop(properties, "sou")
            }
            com.omnifret.gplayer.model.SlideOutType.OutDown -> 
            {
                com.omnifret.gplayer.importer.gplayertex.Atnf.prop(properties, "sod")
            }
            com.omnifret.gplayer.model.SlideOutType.PickSlideDown -> 
            {
                com.omnifret.gplayer.importer.gplayertex.Atnf.prop(properties, "psd")
            }
            com.omnifret.gplayer.model.SlideOutType.PickSlideUp -> 
            {
                com.omnifret.gplayer.importer.gplayertex.Atnf.prop(properties, "psu")
            }
            else -> { }
        }
        if (note.isHammerPullOrigin)
        {
            com.omnifret.gplayer.importer.gplayertex.Atnf.prop(properties, "h")
        }
        if (note.isLeftHandTapped)
        {
            com.omnifret.gplayer.importer.gplayertex.Atnf.prop(properties, "lht")
        }
        if (note.isGhost)
        {
            com.omnifret.gplayer.importer.gplayertex.Atnf.prop(properties, "g")
        }
        when (note.accentuated)
        {
            com.omnifret.gplayer.model.AccentuationType.Normal -> 
            {
                com.omnifret.gplayer.importer.gplayertex.Atnf.prop(properties, "ac")
            }
            com.omnifret.gplayer.model.AccentuationType.Heavy -> 
            {
                com.omnifret.gplayer.importer.gplayertex.Atnf.prop(properties, "hac")
            }
            com.omnifret.gplayer.model.AccentuationType.Tenuto -> 
            {
                com.omnifret.gplayer.importer.gplayertex.Atnf.prop(properties, "ten")
            }
            else -> { }
        }
        if (note.isPalmMute)
        {
            com.omnifret.gplayer.importer.gplayertex.Atnf.prop(properties, "pm")
        }
        if (note.isStaccato)
        {
            com.omnifret.gplayer.importer.gplayertex.Atnf.prop(properties, "st")
        }
        if (note.isLetRing)
        {
            com.omnifret.gplayer.importer.gplayertex.Atnf.prop(properties, "lr")
        }
        if (note.isDead)
        {
            com.omnifret.gplayer.importer.gplayertex.Atnf.prop(properties, "x")
        }
        if (note.isTieDestination)
        {
            com.omnifret.gplayer.importer.gplayertex.Atnf.prop(properties, "t")
        }
        if (note.leftHandFinger >= com.omnifret.gplayer.model.Fingers.Thumb)
        {
            com.omnifret.gplayer.importer.gplayertex.Atnf.prop(properties, "lf", com.omnifret.gplayer.importer.gplayertex.Atnf.numberValue((note.leftHandFinger.toDouble()) + 1.0))
        }
        if (note.rightHandFinger >= com.omnifret.gplayer.model.Fingers.Thumb)
        {
            com.omnifret.gplayer.importer.gplayertex.Atnf.prop(properties, "rf", com.omnifret.gplayer.importer.gplayertex.Atnf.numberValue((note.rightHandFinger.toDouble()) + 1.0))
        }
        if (!note.isVisible)
        {
            com.omnifret.gplayer.importer.gplayertex.Atnf.prop(properties, "hide")
        }
        if (note.isSlurOrigin)
        {
            var slurId: String = """s${(note.id).toTemplate()}"""
            com.omnifret.gplayer.importer.gplayertex.Atnf.prop(properties, "slur", com.omnifret.gplayer.importer.gplayertex.Atnf.identValue(slurId))
        }
        if (note.isSlurDestination)
        {
            var slurId: String = """s${(note.slurOrigin!!.id).toTemplate()}"""
            com.omnifret.gplayer.importer.gplayertex.Atnf.prop(properties, "slur", com.omnifret.gplayer.importer.gplayertex.Atnf.identValue(slurId))
        }
        var skipAccidental: Boolean = note.accidentalMode == com.omnifret.gplayer.model.NoteAccidentalMode.Default || (note.beat.voice.bar.keySignature == com.omnifret.gplayer.model.KeySignature.C && note.accidentalMode == com.omnifret.gplayer.model.NoteAccidentalMode.ForceNatural)
        if (!skipAccidental)
        {
            com.omnifret.gplayer.importer.gplayertex.Atnf.prop(properties, "acc", com.omnifret.gplayer.importer.gplayertex.Atnf.identValue(com.omnifret.gplayer.model.ModelUtils.reverseAccidentalModeMapping.get(note.accidentalMode)!!))
        }
        when (note.ornament)
        {
            com.omnifret.gplayer.model.NoteOrnament.InvertedTurn -> 
            {
                com.omnifret.gplayer.importer.gplayertex.Atnf.prop(properties, "iturn")
            }
            com.omnifret.gplayer.model.NoteOrnament.Turn -> 
            {
                com.omnifret.gplayer.importer.gplayertex.Atnf.prop(properties, "turn")
            }
            com.omnifret.gplayer.model.NoteOrnament.UpperMordent -> 
            {
                com.omnifret.gplayer.importer.gplayertex.Atnf.prop(properties, "umordent")
            }
            com.omnifret.gplayer.model.NoteOrnament.LowerMordent -> 
            {
                com.omnifret.gplayer.importer.gplayertex.Atnf.prop(properties, "lmordent")
            }
            else -> { }
        }
        return properties
    }
    
    /**
     */
    public override fun buildBeatEffects(beat: com.omnifret.gplayer.model.Beat): com.omnifret.gplayer.collections.List<com.omnifret.gplayer.importer.gplayertex.GPlayerTexPropertyNode>{
        var properties: com.omnifret.gplayer.collections.List<com.omnifret.gplayer.importer.gplayertex.GPlayerTexPropertyNode> = com.omnifret.gplayer.collections.List<com.omnifret.gplayer.importer.gplayertex.GPlayerTexPropertyNode>(
        )
        
        when (beat.fade)
        {
            com.omnifret.gplayer.model.FadeType.FadeIn -> 
            {
                com.omnifret.gplayer.importer.gplayertex.Atnf.prop(properties, "f")
            }
            com.omnifret.gplayer.model.FadeType.FadeOut -> 
            {
                com.omnifret.gplayer.importer.gplayertex.Atnf.prop(properties, "fo")
            }
            com.omnifret.gplayer.model.FadeType.VolumeSwell -> 
            {
                com.omnifret.gplayer.importer.gplayertex.Atnf.prop(properties, "vs")
            }
            else -> { }
        }
        if (beat.vibrato == com.omnifret.gplayer.model.VibratoType.Slight)
        {
            com.omnifret.gplayer.importer.gplayertex.Atnf.prop(properties, "v")
        }
        else if (beat.vibrato == com.omnifret.gplayer.model.VibratoType.Wide)
        {
            com.omnifret.gplayer.importer.gplayertex.Atnf.prop(properties, "vw")
        }
        if (beat.slap)
        {
            com.omnifret.gplayer.importer.gplayertex.Atnf.prop(properties, "s")
        }
        if (beat.pop)
        {
            com.omnifret.gplayer.importer.gplayertex.Atnf.prop(properties, "p")
        }
        if (beat.tap)
        {
            com.omnifret.gplayer.importer.gplayertex.Atnf.prop(properties, "tt")
        }
        if (beat.dots >= 2)
        {
            com.omnifret.gplayer.importer.gplayertex.Atnf.prop(properties, "dd")
        }
        else if (beat.dots > 0)
        {
            com.omnifret.gplayer.importer.gplayertex.Atnf.prop(properties, "d")
        }
        if (beat.pickStroke == com.omnifret.gplayer.model.PickStroke.Up)
        {
            com.omnifret.gplayer.importer.gplayertex.Atnf.prop(properties, "su")
        }
        else if (beat.pickStroke == com.omnifret.gplayer.model.PickStroke.Down)
        {
            com.omnifret.gplayer.importer.gplayertex.Atnf.prop(properties, "sd")
        }
        if (beat.hasTuplet)
        {
            com.omnifret.gplayer.importer.gplayertex.Atnf.prop(properties, "tu", com.omnifret.gplayer.importer.gplayertex.Atnf.args(com.omnifret.gplayer.collections.List<com.omnifret.gplayer.importer.gplayertex.IGPlayerTexArgumentValue?>(
                com.omnifret.gplayer.importer.gplayertex.Atnf.number(beat.tupletNumerator), com.omnifret.gplayer.importer.gplayertex.Atnf.number(beat.tupletDenominator))
            ))
        }
        if (beat.hasWhammyBar)
        {
            var tbeArgs: com.omnifret.gplayer.importer.gplayertex.GPlayerTexArgumentList = com.omnifret.gplayer.importer.gplayertex.Atnf.args(com.omnifret.gplayer.collections.List<com.omnifret.gplayer.importer.gplayertex.IGPlayerTexArgumentValue?>(
                com.omnifret.gplayer.importer.gplayertex.Atnf.ident(com.omnifret.gplayer.importer.gplayertex.GPlayerTex1EnumMappings.whammyTypeReversed.get(beat.whammyBarType)!!), com.omnifret.gplayer.importer.gplayertex.Atnf.ident(com.omnifret.gplayer.importer.gplayertex.GPlayerTex1EnumMappings.bendStyleReversed.get(beat.whammyStyle)!!))
            , true)!!
            for (p in beat.whammyBarPoints!!)
            {
                tbeArgs.arguments.push(com.omnifret.gplayer.importer.gplayertex.Atnf.number(p.offset))
                tbeArgs.arguments.push(com.omnifret.gplayer.importer.gplayertex.Atnf.number(p.value))
            }
            com.omnifret.gplayer.importer.gplayertex.Atnf.prop(properties, "tbe", tbeArgs)
        }
        var brushType: String = ""
        when (beat.brushType)
        {
            com.omnifret.gplayer.model.BrushType.BrushUp -> 
            {
                brushType = "bu"
            }
            com.omnifret.gplayer.model.BrushType.BrushDown -> 
            {
                brushType = "bd"
            }
            com.omnifret.gplayer.model.BrushType.ArpeggioUp -> 
            {
                brushType = "au"
            }
            com.omnifret.gplayer.model.BrushType.ArpeggioDown -> 
            {
                brushType = "ad"
            }
            else -> { }
        }
        if (com.omnifret.gplayer.core.TypeHelper.isTruthy(com.omnifret.gplayer.core.TypeHelper.isTruthy(brushType)))
        {
            com.omnifret.gplayer.importer.gplayertex.Atnf.prop(properties, brushType, com.omnifret.gplayer.importer.gplayertex.Atnf.numberValue(beat.brushDuration))
        }
        if (beat.chord != null)
        {
            com.omnifret.gplayer.importer.gplayertex.Atnf.prop(properties, "ch", com.omnifret.gplayer.importer.gplayertex.Atnf.stringValue(beat.chord!!.name))
        }
        if (beat.ottava != com.omnifret.gplayer.model.Ottavia.Regular)
        {
            com.omnifret.gplayer.importer.gplayertex.Atnf.prop(properties, "ot", com.omnifret.gplayer.importer.gplayertex.Atnf.identValue(com.omnifret.gplayer.importer.gplayertex.GPlayerTex1EnumMappings.ottaviaReversed.get(beat.ottava)!!))
        }
        if (beat.hasRasgueado)
        {
            com.omnifret.gplayer.importer.gplayertex.Atnf.prop(properties, "rasg", com.omnifret.gplayer.importer.gplayertex.Atnf.identValue(com.omnifret.gplayer.importer.gplayertex.GPlayerTex1EnumMappings.rasgueadoReversed.get(beat.rasgueado)!!))
        }
        if (beat.text != null)
        {
            com.omnifret.gplayer.importer.gplayertex.Atnf.prop(properties, "txt", com.omnifret.gplayer.importer.gplayertex.Atnf.stringValue(beat.text!!))
        }
        if (beat.lyrics != null && beat.lyrics!!.length > 0)
        {
            if (beat.lyrics!!.length > 1)
            {
                if (true) {
                    var i: Double = 0.0
                    
                    while(i < beat.lyrics!!.length){
                        com.omnifret.gplayer.importer.gplayertex.Atnf.prop(properties, "lyrics", com.omnifret.gplayer.importer.gplayertex.Atnf.args(com.omnifret.gplayer.collections.List<com.omnifret.gplayer.importer.gplayertex.IGPlayerTexArgumentValue?>(
                            com.omnifret.gplayer.importer.gplayertex.Atnf.number(i), com.omnifret.gplayer.importer.gplayertex.Atnf.string(beat.lyrics!![(i).toInt()]))
                        ))
                        i++
                    }
                }
            }
            else 
            {
                com.omnifret.gplayer.importer.gplayertex.Atnf.prop(properties, "lyrics", com.omnifret.gplayer.importer.gplayertex.Atnf.stringValue(beat.lyrics!![(0).toInt()]))
            }
        }
        if (beat.graceType != com.omnifret.gplayer.model.GraceType.None)
        {
            com.omnifret.gplayer.importer.gplayertex.Atnf.prop(properties, "gr", if(beat.graceType == com.omnifret.gplayer.model.GraceType.BeforeBeat)  null else com.omnifret.gplayer.importer.gplayertex.Atnf.identValue(com.omnifret.gplayer.importer.gplayertex.GPlayerTex1EnumMappings.graceTypeReversed.get(beat.graceType)!!))
        }
        if (beat.isTremolo)
        {
            var values: com.omnifret.gplayer.collections.List<com.omnifret.gplayer.importer.gplayertex.IGPlayerTexArgumentValue> = com.omnifret.gplayer.collections.List<com.omnifret.gplayer.importer.gplayertex.IGPlayerTexArgumentValue>(
                com.omnifret.gplayer.importer.gplayertex.Atnf.number(beat.tremoloPicking!!.marks))
            
            if (beat.tremoloPicking!!.style != com.omnifret.gplayer.model.TremoloPickingStyle.Default)
            {
                values.push(com.omnifret.gplayer.importer.gplayertex.Atnf.ident(beat.tremoloPicking!!.style.toString()))
            }
            com.omnifret.gplayer.importer.gplayertex.Atnf.prop(properties, "tp", com.omnifret.gplayer.importer.gplayertex.Atnf.args(((values as com.omnifret.gplayer.collections.List<com.omnifret.gplayer.importer.gplayertex.IGPlayerTexArgumentValue?>))))
        }
        when (beat.crescendo)
        {
            com.omnifret.gplayer.model.CrescendoType.Crescendo -> 
            {
                com.omnifret.gplayer.importer.gplayertex.Atnf.prop(properties, "cre")
            }
            com.omnifret.gplayer.model.CrescendoType.Decrescendo -> 
            {
                com.omnifret.gplayer.importer.gplayertex.Atnf.prop(properties, "dec")
            }
            else -> { }
        }
        if ((beat.voice.bar.index == 0.0 && beat.index == 0.0) || beat.dynamics != beat.previousBeat?.dynamics)
        {
            com.omnifret.gplayer.importer.gplayertex.Atnf.prop(properties, "dy", com.omnifret.gplayer.importer.gplayertex.Atnf.identValue(com.omnifret.gplayer.importer.gplayertex.GPlayerTex1EnumMappings.dynamicValueReversed.get(beat.dynamics)!!))
        }
        var fermata: com.omnifret.gplayer.model.Fermata? = beat.fermata
        if (fermata != null)
        {
            com.omnifret.gplayer.importer.gplayertex.Atnf.prop(properties, "fermata", com.omnifret.gplayer.importer.gplayertex.Atnf.args(com.omnifret.gplayer.collections.List<com.omnifret.gplayer.importer.gplayertex.IGPlayerTexArgumentValue?>(
                com.omnifret.gplayer.importer.gplayertex.Atnf.ident(com.omnifret.gplayer.importer.gplayertex.GPlayerTex1EnumMappings.fermataTypeReversed.get(beat.fermata!!.type)!!), com.omnifret.gplayer.importer.gplayertex.Atnf.number(beat.fermata!!.length))
            ))
        }
        if (beat.isLegatoOrigin)
        {
            com.omnifret.gplayer.importer.gplayertex.Atnf.prop(properties, "legatoorigin")
        }
        for (automation in beat.automations)
        {
            when (automation.type)
            {
                com.omnifret.gplayer.model.AutomationType.Tempo -> 
                {
                    com.omnifret.gplayer.importer.gplayertex.Atnf.prop(properties, "tempo", com.omnifret.gplayer.importer.gplayertex.Atnf.args(com.omnifret.gplayer.collections.List<com.omnifret.gplayer.importer.gplayertex.IGPlayerTexArgumentValue?>(
                        com.omnifret.gplayer.importer.gplayertex.Atnf.number(automation.value), if(automation.text.length.toDouble() == 0.0)  null else com.omnifret.gplayer.importer.gplayertex.Atnf.string(automation.text))
                    ))
                }
                com.omnifret.gplayer.model.AutomationType.Volume -> 
                {
                    com.omnifret.gplayer.importer.gplayertex.Atnf.prop(properties, "volume", com.omnifret.gplayer.importer.gplayertex.Atnf.numberValue(automation.value))
                }
                com.omnifret.gplayer.model.AutomationType.Instrument -> 
                {
